CustomField.formula:
IF(
  ISBLANK(Vendor_Actual_Completion_Date__c ),

  /* Not completed yet */
  IF(
    TODAY() > Vendor_Work_End_Date__c ,
    "Overdue (" & TEXT(TODAY() - Vendor_Work_End_Date__c ) & " days)",
    IF(
      (Vendor_Work_End_Date__c - TODAY()) < 15,
      "High Risk",
      "Low Risk"
    )
  ),

  /* Completed */
  IF(
    Vendor_Actual_Completion_Date__c > Vendor_Work_End_Date__c ,
    "Completed – Delayed (" & TEXT(Vendor_Actual_Completion_Date__c - Vendor_Work_End_Date__c ) & " days)",
    "Completed – On Time"
  )
)
